import{_ as a,a as e,b as t,c as o,d as n,e as l}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as r,o as s,c as p,a2 as d}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Geolocalizzazione IP e gestione utenti","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/ip-geolocation-and-user-management.md","filePath":"it-IT/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"it-IT/Other/ip-geolocation-and-user-management.md"};function u(g,i,m,h,z,b){return s(),p("div",null,[...i[0]||(i[0]=[d('<h1 id="geolocalizzazione-ip-e-gestione-utenti" tabindex="-1">Geolocalizzazione IP e gestione utenti <a class="header-anchor" href="#geolocalizzazione-ip-e-gestione-utenti" aria-label="Permalink to &quot;Geolocalizzazione IP e gestione utenti&quot;">​</a></h1><p>La geolocalizzazione IP trasforma gli indirizzi IP nei record di upload, nei dispositivi di login e in log simili in posizioni approssimative.</p><p>Dopo la configurazione, il pannello admin mostra in modo più chiaro origine di upload e accessi. Gestione utenti permette anche di bloccare o ripristinare l&#39;accesso upload per IP sospetti.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="Geolocalizzazione IP" loading="lazy"></p><h2 id="impostazioni-disponibili" tabindex="-1">Impostazioni disponibili <a class="header-anchor" href="#impostazioni-disponibili" aria-label="Permalink to &quot;Impostazioni disponibili&quot;">​</a></h2><p>Il nuovo flusso di geolocalizzazione IP supporta più sorgenti, invece di dipendere da un solo servizio mappe.</p><table tabindex="0"><thead><tr><th>Impostazione</th><th>Scopo</th></tr></thead><tbody><tr><td>Lingua geolocalizzazione IP</td><td>Sceglie la lingua di visualizzazione, per esempio inglese, cinese semplificato, giapponese, francese e altre.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind per MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Chiave Tencent Location Service, utile per indirizzi cinesi e IP della Cina continentale.</td></tr><tr><td>ipapi Key</td><td>Chiave APILayer ipapi. Supporta geolocalizzazione IP multilingue.</td></tr></tbody></table><p>Compila solo i servizi che ti servono. Non è necessario riempire tutti i campi.</p><p>Senza chiavi, ImgBed prova comunque sorgenti gratuite integrate, ma stabilità, supporto lingua e precisione possono essere inferiori rispetto a un servizio configurato da te.</p><h2 id="scelte-consigliate" tabindex="-1">Scelte consigliate <a class="header-anchor" href="#scelte-consigliate" aria-label="Permalink to &quot;Scelte consigliate&quot;">​</a></h2><p>Se ti servono soprattutto indirizzi cinesi:</p><ol><li>Imposta la lingua su cinese semplificato.</li><li>Configura Tencent Map Key.</li><li>Opzionalmente aggiungi MaxMind o ipapi come fallback.</li></ol><p>Se ti servono indirizzi inglesi o multilingue:</p><ol><li>Scegli la lingua necessaria.</li><li>Configura MaxMind Account ID e License Key.</li><li>Aggiungi ipapi Key se vuoi risultati multilingue migliori.</li></ol><h2 id="configurare-maxmind" tabindex="-1">Configurare MaxMind <a class="header-anchor" href="#configurare-maxmind" aria-label="Permalink to &quot;Configurare MaxMind&quot;">​</a></h2><p>MaxMind richiede:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Trova l&#39;Account ID nella dashboard MaxMind e genera una License Key dalla pagina License Keys.</p><p><img src="`+e+'" alt="Configurazione chiave MaxMind" loading="lazy"></p><p>Dopo la generazione, incolla Account ID e License Key in ImgBed e salva.</p><p>Il piano gratuito MaxMind va bene per l&#39;uso quotidiano, ma ha limiti di richieste. Se la quota viene superata, ImgBed prova le altre sorgenti disponibili.</p><h2 id="configurare-ipapi" tabindex="-1">Configurare ipapi <a class="header-anchor" href="#configurare-ipapi" aria-label="Permalink to &quot;Configurare ipapi&quot;">​</a></h2><p>ipapi usa una API Key APILayer.</p><p>Apri la console ipapi e copia la API Key mostrata.</p><p><img src="'+t+'" alt="Configurazione ipapi" loading="lazy"></p><p>Incollala nel campo <code>ipapi Key</code> in ImgBed e salva.</p><p>ipapi supporta geolocalizzazione IP multilingue ed è utile quando vuoi indirizzi nella lingua selezionata. Anche il piano gratuito ha limiti. Se la quota termina, ImgBed continua con altre sorgenti disponibili.</p><h2 id="configurare-tencent-map-key" tabindex="-1">Configurare Tencent Map Key <a class="header-anchor" href="#configurare-tencent-map-key" aria-label="Permalink to &quot;Configurare Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key è utile per indirizzi cinesi, soprattutto IP della Cina continentale.</p><p>Quando crei una chiave in Tencent Location Service, abilita:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Dopo la creazione, incolla la chiave in <code>Tencent Map Key</code> e salva.</p><p>Se ti basta una geolocalizzazione IP cinese di base, Tencent Map Key è sufficiente per iniziare.</p><h2 id="cosa-controllare-in-gestione-utenti" tabindex="-1">Cosa controllare in Gestione utenti <a class="header-anchor" href="#cosa-controllare-in-gestione-utenti" aria-label="Permalink to &quot;Cosa controllare in Gestione utenti&quot;">​</a></h2><p>Gestione utenti è disponibile in alto nel pannello admin.</p><p><img src="'+o+'" alt="Gestione utenti" loading="lazy"></p><p>Mostra l&#39;attività di upload per IP:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Descrizione</th></tr></thead><tbody><tr><td>Origine IP</td><td>IP sorgente dell&#39;uploader.</td></tr><tr><td>Indirizzo</td><td>Posizione approssimativa risolta dall&#39;IP.</td></tr><tr><td>Dimensione upload totale</td><td>Dimensione totale dei file caricati da questo IP.</td></tr><tr><td>Numero upload</td><td>Numero di upload da questo IP.</td></tr><tr><td>Upload consentito</td><td>Attivo significa upload permessi. Disattivo significa upload bloccati.</td></tr></tbody></table><p>Clicca la freccia a sinistra per espandere la lista dei file caricati da quell&#39;IP.</p><p>La lista mostra nome file, anteprima, dimensione, risultato moderazione, stato file e ora upload. Se gli upload sembrano sospetti, espandi prima l&#39;IP, controlla i file e poi decidi se bloccare ulteriori upload.</p><p>Se un IP è sospetto, disattiva <code>Upload allowed</code>. I futuri upload da quell&#39;IP verranno bloccati.</p><h2 id="ricerca-ordinamento-e-filtri-avanzati" tabindex="-1">Ricerca, ordinamento e filtri avanzati <a class="header-anchor" href="#ricerca-ordinamento-e-filtri-avanzati" aria-label="Permalink to &quot;Ricerca, ordinamento e filtri avanzati&quot;">​</a></h2><p>In alto in Gestione utenti puoi cercare per IP sorgente o indirizzo.</p><p>Ordina per tempo, numero upload o dimensione totale per trovare uploader recenti, molto frequenti o con uso elevato.</p><p>Per indagini più precise, apri i filtri avanzati.</p><p><img src="'+n+'" alt="Filtri avanzati" loading="lazy"></p><p>I filtri avanzati supportano:</p><table tabindex="0"><thead><tr><th>Filtro</th><th>Uso</th></tr></thead><tbody><tr><td>Intervallo tempo</td><td>Mostra IP che hanno caricato file in un periodo selezionato.</td></tr><tr><td>Stato accesso</td><td>Filtra per stati normali, bloccati e simili.</td></tr><tr><td>Allow/block list</td><td>Filtra per allowlist, blocklist o non impostato.</td></tr><tr><td>Tipo file</td><td>Mostra IP che hanno caricato immagini, video, audio, documenti, codice o altri file.</td></tr><tr><td>Dimensione file</td><td>Filtra per intervallo di dimensione caricata.</td></tr><tr><td>Rating età</td><td>Filtra per non impostato, General, R12+, R16+, R18 e simili.</td></tr><tr><td>Stato file</td><td>Filtra per stato file attuale per analizzare file anomali.</td></tr></tbody></table><p>Clicca <code>Apply Filters</code> per applicare. Usa <code>Reset</code> per tornare a tutti i dati.</p><h2 id="vista-mobile" tabindex="-1">Vista mobile <a class="header-anchor" href="#vista-mobile" aria-label="Permalink to &quot;Vista mobile&quot;">​</a></h2><p>Su mobile, Gestione utenti passa a layout a schede.</p><p><img src="'+l+`" alt="Gestione utenti mobile" loading="lazy"></p><p>Ogni scheda mostra IP, indirizzo, dimensione totale upload, numero upload e interruttore upload consentito. Puoi gestire gli utenti senza scorrimento orizzontale della tabella.</p><h2 id="se-la-posizione-sembra-sbagliata" tabindex="-1">Se la posizione sembra sbagliata <a class="header-anchor" href="#se-la-posizione-sembra-sbagliata" aria-label="Permalink to &quot;Se la posizione sembra sbagliata&quot;">​</a></h2><p>La geolocalizzazione IP è approssimativa. Non è un indirizzo stradale preciso.</p><p>Se l&#39;utente passa da proxy, data center, server cloud o rete transfrontaliera, la posizione mostrata può differire da quella reale.</p><p>Usa questa funzione per capire l&#39;origine indicativa, trovare upload anomali e supportare decisioni di blocco. Non trattarla come tracciamento preciso.</p><h2 id="casi-comuni" tabindex="-1">Casi comuni <a class="header-anchor" href="#casi-comuni" aria-label="Permalink to &quot;Casi comuni&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caso</th><th>Significato</th></tr></thead><tbody><tr><td>Indirizzo vuoto</td><td>L&#39;IP potrebbe non essere ancora risolto o la sorgente corrente non è disponibile.</td></tr><tr><td>Lingua indirizzo errata</td><td>Controlla la lingua geolocalizzazione IP e se è configurata una sorgente che la supporta.</td></tr><tr><td>Indirizzo data center</td><td>Molti proxy, server cloud e crawler appaiono come data center o ISP.</td></tr><tr><td>Numero upload alto</td><td>Controlla attentamente l&#39;IP e blocca gli upload se necessario.</td></tr><tr><td>Dimensione upload alta</td><td>Ordina o filtra, espandi l&#39;IP e ispeziona i file specifici.</td></tr><tr><td>Ripristino dopo blocco</td><td>Riattiva <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri IP Geolocation in Other Settings</span></span>
<span class="line"><span>-&gt; Scegli la lingua di geolocalizzazione IP</span></span>
<span class="line"><span>-&gt; Compila MaxMind, Tencent Map o ipapi secondo necessità</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Apri Gestione utenti</span></span>
<span class="line"><span>-&gt; Controlla IP, indirizzo, dimensione totale e numero upload</span></span>
<span class="line"><span>-&gt; Usa ricerca, ordinamento o filtri avanzati per trovare IP anomali</span></span>
<span class="line"><span>-&gt; Consenti o blocca upload secondo necessità</span></span></code></pre></div>`,64)])])}const P=r(c,[["render",u]]);export{I as __pageData,P as default};
